// W1 — Build Input
// Edita los valores de `input` para probar distintos payloads.
// El resto del workflow toma estos valores tal cual.
//
// CONVENCIÓN id_cabana:
//   - id_cabana > 0  -> filtrar por esa cabaña (ej. 17 = Bamboo)
//   - id_cabana = 0  -> TODAS las cabañas
// Esta convención es un workaround del límite de n8n Query Parameters
// (no soporta NULL real). La función SQL recibe NULL gracias a
// NULLIF($3::BIGINT, 0) en la query.

// === EDITAR ESTOS VALORES PARA CADA PRUEBA ===
const input = {
  fecha_desde: "2026-06-07",
  fecha_hasta: "2026-06-14",
  id_cabana: 17,
  source_event: "n8n_w01_consultar_disponibilidad_manual"
};
// =============================================

return [{ json: input }];

// W1 — Build Response
// Agrupa las N filas devueltas por obtener_disponibilidad_rango() en un único
// objeto con la estructura definida en
// Docs/Implementacion/6C_REESCRITURA_WORKFLOWS_SUPABASE.md v1.2 Sección 5.6.
//
// NOTA W1: source_event NO se registra en log_cambios porque la función es
// read-only y no recibe ese parámetro. Queda solo para trazabilidad en n8n.
//
// n8n no reinterpreta semántica: lo que la función devuelve (tipo_dia, estado,
// horas, etc.) llega tal cual al output.
//
// CONVENCIÓN id_cabana en la respuesta:
//   - Si Build Input mandó id_cabana = 0 (todas), respondemos id_cabana: null.
//   - Si Build Input mandó id_cabana > 0, respondemos ese valor.
//
// FILTER DEFENSIVO: si el nodo Postgres tiene "Always Output Data" activado y
// la función devolvió 0 filas, n8n manda un item con json vacío. Lo filtramos
// para que total_dias y dias reflejen el conteo real.

const buildInput = $('Build Input').first().json;
const dias = items
  .map(item => item.json)
  .filter(d => d && Object.keys(d).length > 0);
const idCabanaInput = buildInput.id_cabana;
const idCabanaOut = (idCabanaInput === 0 || idCabanaInput === '0') ? null : idCabanaInput;

return [
  {
    json: {
      ok: true,
      workflow: 'vita_w01_consultar_disponibilidad_supabase',
      source_event: buildInput.source_event,
      result: {
        rango: {
          fecha_desde: buildInput.fecha_desde,
          fecha_hasta: buildInput.fecha_hasta
        },
        id_cabana: idCabanaOut,
        total_dias: dias.length,
        dias: dias
      },
      executed_at: new Date().toISOString()
    }
  }
];
